Consider the following JavaScript code. What will be the output of the two `console.log` statements?

javascript
function createCounter() {
  let count = 0;
  return {
    increment: function() {
      count++;
    },
    decrement: function() {
      count--;
    },
    getCount: function() {
      return count;
    }
  };
}

const counter1 = createCounter();
const counter2 = createCounter();

counter1.increment();
counter1.increment();
counter2.decrement();
counter1.increment();

console.log(counter1.getCount());
console.log(counter2.getCount());
